import{_ as e,o as a,c as n,a2 as i}from"./chunks/framework.D36jym0Z.js";const c=JSON.parse('{"title":"Configuration Model","description":"","frontmatter":{},"headers":[],"relativePath":"platform-concepts/configuration-model.md","filePath":"platform-concepts/configuration-model.md","lastUpdated":1784629191000}'),s={name:"platform-concepts/configuration-model.md"};function l(o,t,d,r,p,g){return a(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="configuration-model" tabindex="-1">Configuration Model <a class="header-anchor" href="#configuration-model" aria-label="Permalink to &quot;Configuration Model&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Under development</p><p>The formal configuration model is being defined by the core team. This page describes the current working model.</p></div><p>LightMem2 uses a <strong>layered configuration model</strong> where settings cascade from broad defaults to specific overrides. Each layer overrides the previous one.</p><h2 id="configuration-layers" tabindex="-1">Configuration Layers <a class="header-anchor" href="#configuration-layers" aria-label="Permalink to &quot;Configuration Layers&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│  4. User overrides              │  ← Highest priority</span></span>
<span class="line"><span>│     (CLI flags, env vars)       │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  3. Plugin-level config         │</span></span>
<span class="line"><span>│     (plugin&#39;s own settings)     │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  2. Host-level config           │</span></span>
<span class="line"><span>│     (host&#39;s native config file) │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│  1. Platform defaults           │  ← Lowest priority</span></span>
<span class="line"><span>│     (built-in sensible defaults)│</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span></code></pre></div><h2 id="where-configuration-lives" tabindex="-1">Where Configuration Lives <a class="header-anchor" href="#where-configuration-lives" aria-label="Permalink to &quot;Where Configuration Lives&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Host</th><th style="text-align:left;">Config File</th><th style="text-align:left;">Plugin Config</th></tr></thead><tbody><tr><td style="text-align:left;">OpenClaw</td><td style="text-align:left;"><code>~/.openclaw/openclaw.json</code></td><td style="text-align:left;">Inside the host config</td></tr><tr><td style="text-align:left;">Codex</td><td style="text-align:left;"><code>~/.codex/tokenpilot.json</code></td><td style="text-align:left;">Separate plugin config file</td></tr><tr><td style="text-align:left;">Claude Code</td><td style="text-align:left;"><code>~/.claude/tokenpilot.json</code></td><td style="text-align:left;">Separate plugin config file</td></tr></tbody></table><h2 id="common-plugin-settings" tabindex="-1">Common Plugin Settings <a class="header-anchor" href="#common-plugin-settings" aria-label="Permalink to &quot;Common Plugin Settings&quot;">​</a></h2><p>These settings exist for all plugins:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;normal&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;logLevel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;info&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>TokenPilot adds its own settings (see <a href="/LightMem2/plugin-catalog/tokenpilot/configuration">TokenPilot Configuration</a>).</p><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><p>Adapters use environment variables for non-default paths:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Variable</th><th style="text-align:left;">Purpose</th><th style="text-align:left;">Host</th></tr></thead><tbody><tr><td style="text-align:left;"><code>LIGHTMEM2_OPENCLAW_HOME</code></td><td style="text-align:left;">Custom OpenClaw home dir</td><td style="text-align:left;">OpenClaw</td></tr><tr><td style="text-align:left;"><code>OPENCLAW_CONFIG_PATH</code></td><td style="text-align:left;">Custom config path</td><td style="text-align:left;">OpenClaw</td></tr><tr><td style="text-align:left;"><code>CODEX_CONFIG_PATH</code></td><td style="text-align:left;">Custom config.toml path</td><td style="text-align:left;">Codex</td></tr><tr><td style="text-align:left;"><code>CODEX_HOOKS_CONFIG_PATH</code></td><td style="text-align:left;">Custom hooks.json path</td><td style="text-align:left;">Codex</td></tr><tr><td style="text-align:left;"><code>TOKENPILOT_CODEX_CONFIG</code></td><td style="text-align:left;">Custom tokenpilot.json path</td><td style="text-align:left;">Codex</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SETTINGS_PATH</code></td><td style="text-align:left;">Custom settings.json path</td><td style="text-align:left;">Claude Code</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_MCP_CONFIG_PATH</code></td><td style="text-align:left;">Custom .claude.json path</td><td style="text-align:left;">Claude Code</td></tr><tr><td style="text-align:left;"><code>TOKENPILOT_CLAUDE_CODE_CONFIG</code></td><td style="text-align:left;">Custom tokenpilot.json path</td><td style="text-align:left;">Claude Code</td></tr></tbody></table><h2 id="resolving-configuration" tabindex="-1">Resolving Configuration <a class="header-anchor" href="#resolving-configuration" aria-label="Permalink to &quot;Resolving Configuration&quot;">​</a></h2><p>At runtime, LightMem2:</p><ol><li>Reads platform defaults</li><li>Reads the host config file</li><li>Reads the plugin config file</li><li>Applies environment variable overrides</li><li>Applies CLI flag overrides</li></ol><p>The resolved config is what plugins see at runtime.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/plugin-catalog/tokenpilot/configuration">TokenPilot Configuration</a> — TokenPilot-specific settings</li><li><a href="/LightMem2/user-guide/plugin-configuration">Plugin Configuration</a> — how to change plugin settings</li></ul>`,20)])])}const f=e(s,[["render",l]]);export{c as __pageData,f as default};
